const envelope = items[0]?.json ?? {};
const payload = envelope?.body ?? {};
const formData = payload?.data ?? {};
const fields = Array.isArray(formData?.fields) ? formData.fields : [];

const FIELD_KEYS = Object.freeze({
  TRAVEL_LIFESTYLE: 'question_y6lBLd',
  AGE_GROUP: 'question_XDepXz',
  TRAINING_ENVIRONMENT: 'question_8KdXOr',
  TRAINING_IMPLEMENTATION: 'question_0xEKXA',
  FOCUS: 'question_zqKklg',
  ACTIVITY_LEVEL: 'question_lyNxQX',
  ACTIVITY_TYPE: 'question_R0zApQ',
  DAILY_SCHEDULE: 'question_oyAqWN',
  SLEEP_AMOUNT: 'question_GzrZWO',
  GENDER: 'question_V0ZKg6',
  CYCLE_ADJUST: 'question_DNr5Nb',
  CYCLE_PHASE: 'question_lyoLy5',
  MINDFUL_AREAS: 'question_P6A7Kx',
  NAME: 'question_R0XR0l',
  EMAIL: 'question_jyBjN1',
});

function normalizeText(value) {
  if (value == null) { return null; }
  return String(value)
    .replace(/\u00A0/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function buildFieldMap(fieldList) {
  const result = {};
  for (const field of fieldList) {
    if (field?.key) { result[field.key] = field; }
  }
  return result;
}

function extractMultipleChoice(field) {
  if (!field) { return null; }
  const selectedIds = Array.isArray(field.value) ? field.value : field.value != null ? [field.value] : [];
  if (selectedIds.length === 0) { return null; }
  const options = Array.isArray(field.options) ? field.options : [];
  const optionTextById = {};
  for (const option of options) {
    if (option?.id) { optionTextById[option.id] = normalizeText(option.text); }
  }
  const selectedTexts = selectedIds.map(id => optionTextById[id] ?? null).filter(Boolean);
  if (selectedTexts.length === 0) { return null; }
  return selectedTexts.length === 1 ? selectedTexts[0] : selectedTexts;
}

function extractScalar(field) {
  if (!field || field.value == null) { return null; }
  return typeof field.value === 'string' ? normalizeText(field.value) : field.value;
}

function extractValue(field) {
  if (!field) { return null; }
  switch (field.type) {
    case 'MULTIPLE_CHOICE': return extractMultipleChoice(field);
    case 'INPUT_TEXT':
    case 'INPUT_EMAIL': return extractScalar(field);
    default: return extractScalar(field);
  }
}

const fieldMap = buildFieldMap(fields);

return [{
  json: {
    tally: {
      eventId: payload.eventId ?? null,
      eventType: payload.eventType ?? null,
      createdAt: payload.createdAt ?? null,
      responseId: formData.responseId ?? null,
      submissionId: formData.submissionId ?? null,
      respondentId: formData.respondentId ?? null,
      formId: formData.formId ?? null,
      formName: normalizeText(formData.formName),
      createdAtFormResponse: formData.createdAt ?? null,
    },
    lead: {
      name: extractValue(fieldMap[FIELD_KEYS.NAME]),
      email: extractValue(fieldMap[FIELD_KEYS.EMAIL]),
      travelLifestyle: extractValue(fieldMap[FIELD_KEYS.TRAVEL_LIFESTYLE]),
      ageGroup: extractValue(fieldMap[FIELD_KEYS.AGE_GROUP]),
      trainingEnvironment: extractValue(fieldMap[FIELD_KEYS.TRAINING_ENVIRONMENT]),
      trainingImplementation: extractValue(fieldMap[FIELD_KEYS.TRAINING_IMPLEMENTATION]),
      focus: extractValue(fieldMap[FIELD_KEYS.FOCUS]),
      activityLevel: extractValue(fieldMap[FIELD_KEYS.ACTIVITY_LEVEL]),
      activityType: extractValue(fieldMap[FIELD_KEYS.ACTIVITY_TYPE]),
      dailySchedule: extractValue(fieldMap[FIELD_KEYS.DAILY_SCHEDULE]),
      sleepAmount: extractValue(fieldMap[FIELD_KEYS.SLEEP_AMOUNT]),
      gender: extractValue(fieldMap[FIELD_KEYS.GENDER]),
      cycleAdjust: extractValue(fieldMap[FIELD_KEYS.CYCLE_ADJUST]),
      cyclePhase: extractValue(fieldMap[FIELD_KEYS.CYCLE_PHASE]),
      mindfulAreas: extractValue(fieldMap[FIELD_KEYS.MINDFUL_AREAS]),
    }
  }
}];

const payload = items[0].json;
const lead    = payload.lead || {};

const GOAL_MAP = {
  'Energize & Refocus':      'energy',
  'De-Stress & Reset':       'destress',
  'Posture & Mobility Flow': 'posture',
  'Stay Fit & Active':       'active',
  'Core & Balance':          'core',
};
const SPACE_MAP = {
  'Indoor':             'indoor',
  'Outdoors':           'outdoors',
  'Mixed environment':  'mixed',
  'Mixed':              'mixed',
  'Indoors (hotel room, Airbnb, apartment)': 'indoor',
};
const EQUIP_MAP = {
  'Bodyweight only':             'none',
  'Bodyweight + everyday items': 'everyday_items',
  'Bodyweight + Everyday Items': 'everyday_items',
};
const LEVEL_MAP = {
  'Beginner':     'beginner',
  'Intermediate': 'intermediate',
  'Advanced':     'advanced',
  'Intermediate (active, but inconsistent)': 'intermediate',
  'Beginner (just starting out)':            'beginner',
  'Advanced (very consistent)':              'advanced',
};
const CONTRA_MAP = {
  'Low Back':               'low_back_pain',
  'Low back sensitivity':   'low_back_pain',
  'Knees':                  'knee_pain',
  'Knee sensitivity':       'knee_pain',
  'Shoulders':              'shoulders_pain',
  'Shoulders sensitivity':  'shoulders_pain',
  'High Stress':            'stress',
  'High Stress / fatigue':  'stress',
  'None, feeling good':      null,
  'None':                    null,
};
const SLEEP_MAP = {
  'Less than 5 hours': 'very_low',
  'Under 5 hours':     'very_low',
  '5 hours':           'very_low',
  '6-7 hours':         'normal',
  '6\u20137 hours':    'normal',
  '8+ hours':          'high',
  '8 or more':         'high',
};
const MOVEMENT_MAP = {
  'Cardio':                                        'cardio',
  'Resistance':                                    'resistance',
  'Resistance / strength (weights, bodyweights)': 'resistance',
  'Yoga / Pilates':                                'mobility',
  'Yoga/Pilates':                                  'mobility',
  'Mixed':                                         'mix',
  'Balanced routine':                              'mix',
};
const CYCLE_MAP = {
  'Menstrual phase':  'menstrual',
  'Follicular phase': 'follicular',
  'Ovulatory phase':  'ovulatory',
  'Luteal phase':     'luteal',
  'Not applicable':   'none',
};

const rawAreas = Array.isArray(lead.mindfulAreas)
  ? lead.mindfulAreas
  : lead.mindfulAreas
    ? [lead.mindfulAreas]
    : [];

const user_profile = {
  primary_goal:      GOAL_MAP[lead.focus]                   || lead.focus                                      || null,
  space:             SPACE_MAP[lead.trainingEnvironment]    || (lead.trainingEnvironment   || '').toLowerCase() || null,
  equipment:         EQUIP_MAP[lead.trainingImplementation] || (lead.trainingImplementation || '').toLowerCase() || null,
  level:             LEVEL_MAP[lead.activityLevel]          || (lead.activityLevel         || '').toLowerCase() || 'beginner',
  movement_type:     MOVEMENT_MAP[lead.activityType]        || (lead.activityType          || '').toLowerCase() || null,
  sleep_bucket:      SLEEP_MAP[lead.sleepAmount]            || 'normal',
  sex:               (lead.gender || '').toLowerCase()      || 'undisclosed',
  cycle_phase:       CYCLE_MAP[lead.cyclePhase]             || 'none',
  contraindications: rawAreas.map(a => CONTRA_MAP[a] ?? null).filter(Boolean),
  lifestyle:         (lead.travelLifestyle || '').toLowerCase().replace(/\s+/g, '_') || null,
  age_group:         (lead.ageGroup        || '').toLowerCase().replace(/\s+/g, '_') || null,
};

return [{
  json: {
    name:          lead.name  || 'Unknown',
    email:         lead.email || 'unknown@example.com',
    status:        'new',
    tally_payload: JSON.stringify(payload),
    user_profile:  JSON.stringify(user_profile),
  }
}];

// Get user profile
const buildRecord = $('Build DB Record').first().json;
const profile = JSON.parse(buildRecord.user_profile);
const email = buildRecord.email;

// Movement type normalization (NocoDB: 'strength', quiz maps to: 'resistance')
const mvTypeNorm = { resistance: 'strength', 'balanced routine': 'mix', mix: 'mix' };
const userMovType = mvTypeNorm[profile.movement_type] || profile.movement_type;

// Space filter values from quiz mapping
const spaceMap = {
  indoor:   ['close_space', 'all'],
  outdoors: ['outdoors', 'open_space', 'all'],
  mixed:    ['close_space', 'outdoors', 'open_space', 'all']
};
const allowedSpaces = spaceMap[profile.space] || ['all'];

// Equipment filter values
const equipMap = {
  none:           ['none'],
  everyday_items: ['none', 'everyday_items', 'backpack']
};
const allowedEquip = equipMap[profile.equipment] || ['none'];

// Level progression by week (4 weeks)
const levelProgress = {
  beginner:     [['beginner'], ['beginner'], ['beginner'], ['beginner']],
  intermediate: [['beginner'], ['beginner', 'intermediate'], ['intermediate'], ['intermediate', 'advanced']],
  advanced:     [['intermediate'], ['intermediate', 'advanced'], ['advanced'], ['advanced']]
};
const weekLevels = levelProgress[profile.level] || levelProgress.beginner;

// Contraindication pain keywords
const contraPainKeywords = (profile.contraindications || [])
  .filter(c => c !== 'stress')
  .map(c => {
    if (c === 'low_back_pain') return 'low back';
    if (c === 'knee_pain') return 'knee';
    if (c === 'shoulders_pain') return 'shoulders';
    return c.replace(/_/g, ' ');
  });

// Intensity exclusion rule
const excludeHighIntensity =
  (profile.contraindications || []).includes('stress') ||
  profile.sleep_bucket === 'very_low' ||
  (profile.sex === 'female' && ['menstrual', 'luteal'].includes(profile.cycle_phase));

// Load all exercises from 4 paged requests
const allExercises = [
  ...($('Fetch Exercises p1').first().json.list || []),
  ...($('Fetch Exercises p2').first().json.list || []),
  ...($('Fetch Exercises p3').first().json.list || []),
  ...($('Fetch Exercises p4').first().json.list || [])
];

// Check exercise against user contraindications
function matchesContra(ex) {
  if (contraPainKeywords.length === 0) return true;
  if (!ex.contraindications) return true;
  const exContra = ex.contraindications.toLowerCase();
  return !contraPainKeywords.some(k => exContra.includes(k));
}

// Filter warmup pool
function getWarmupPool() {
  return allExercises.filter(ex => {
    if (ex.primary_goal !== 'warmup') return false;
    if (!allowedSpaces.includes(ex.space)) return false;
    if (!allowedEquip.includes(ex.equipment)) return false;
    if (!matchesContra(ex)) return false;
    if (excludeHighIntensity && ex.intensity === 'high') return false;
    return true;
  });
}

// Filter main pool for a specific goal and week level
function getMainPool(goal, weekLevel) {
  return allExercises.filter(ex => {
    if (ex.primary_goal !== goal) return false;
    if (!allowedSpaces.includes(ex.space)) return false;
    if (!allowedEquip.includes(ex.equipment)) return false;
    if (!weekLevel.includes(ex.level)) return false;
    if (userMovType && userMovType !== 'mix' && ex.movement_type !== userMovType) return false;
    if (!matchesContra(ex)) return false;
    if (excludeHighIntensity && ex.intensity === 'high') return false;
    return true;
  });
}

// Fallback goal groups (per spec)
const fallbackMap = {
  energy:  ['energy', 'active'],
  active:  ['active', 'energy'],
  destress: ['destress', 'posture', 'core'],
  posture:  ['posture', 'destress', 'core'],
  core:     ['core', 'destress', 'posture']
};
const goalFallbacks = fallbackMap[profile.primary_goal] || [profile.primary_goal];

// Body focus slot rules per goal (sessions: morning, midday, afternoon, evening)
const slotBodyFocus = {
  energy:  [['full_body'], ['upper_body', 'full_body'], ['full_body'], ['full_body']],
  destress:[['full_body'], ['upper_body', 'full_body'], ['full_body'], ['full_body']],
  posture: [['full_body'], ['lower_body', 'full_body'], ['upper_body', 'full_body'], ['full_body']],
  active:  [['lower_body', 'full_body'], ['upper_body', 'full_body'], ['full_body'], ['full_body']],
  core:    [['full_body'], ['lower_body', 'full_body'], ['full_body'], ['full_body']]
};
const bodyFocusRules = slotBodyFocus[profile.primary_goal]
  || [['full_body'], ['full_body'], ['full_body'], ['full_body']];

const sessions = ['morning', 'midday', 'afternoon', 'evening'];

function pickRandom(arr) {
  if (!arr || arr.length === 0) return null;
  return arr[Math.floor(Math.random() * arr.length)];
}

// Build 4-week plan
const globalUsedMainIds = new Set(); // anti-repetition across weeks
const warmupPool = getWarmupPool();
const plan = {};

for (let w = 0; w < 4; w++) {
  const weekNum = w + 1;
  const weekLevel = weekLevels[w];

  // Build main pool with goal fallback
  let mainPool = [];
  for (const goal of goalFallbacks) {
    const pool = getMainPool(goal, weekLevel);
    const fresh = pool.filter(e => !mainPool.find(m => m.ex_id === e.ex_id));
    mainPool = [...mainPool, ...fresh];
    if (mainPool.length >= 4) break;
  }

  // Prefer exercises not used in previous weeks
  const freshMain = mainPool.filter(e => !globalUsedMainIds.has(e.ex_id));
  const effectiveMain = freshMain.length >= 4 ? freshMain : mainPool;

  const weekUsedWarmupIds = new Set();
  const weekUsedMainIds = new Set();
  const weekPlan = {};

  for (let s = 0; s < 4; s++) {
    // Warmup: unique within week, repeats between weeks allowed
    const warmupCandidates = warmupPool.filter(e => !weekUsedWarmupIds.has(e.ex_id));
    const wu = pickRandom(warmupCandidates.length > 0 ? warmupCandidates : warmupPool);
    if (wu) weekUsedWarmupIds.add(wu.ex_id);

    // Main: match body_focus slot rule, fallback to any unused, then any
    const slotFocus = bodyFocusRules[s];
    let mainCandidates = effectiveMain.filter(e =>
      !weekUsedMainIds.has(e.ex_id) && slotFocus.includes(e.body_focus)
    );
    if (mainCandidates.length === 0) {
      mainCandidates = effectiveMain.filter(e => !weekUsedMainIds.has(e.ex_id));
    }
    if (mainCandidates.length === 0) {
      mainCandidates = mainPool;
    }
    const mx = pickRandom(mainCandidates);
    if (mx) {
      weekUsedMainIds.add(mx.ex_id);
      globalUsedMainIds.add(mx.ex_id);
    }

    weekPlan[sessions[s]] = {
      warmup: wu ? {
        ex_id: wu.ex_id,
        name: wu.name,
        body_focus: wu.body_focus,
        level: wu.level,
        intensity: wu.intensity,
        movement_type: wu.movement_type,
        image_url: wu.image_url,
        cues: wu.cues
      } : null,
      main: mx ? {
        ex_id: mx.ex_id,
        name: mx.name,
        body_focus: mx.body_focus,
        level: mx.level,
        intensity: mx.intensity,
        movement_type: mx.movement_type,
        primary_goal: mx.primary_goal,
        image_url: mx.image_url,
        cues: mx.cues
      } : null
    };
  }
  plan[`week_${weekNum}`] = weekPlan;
}

return [{ json: { program_plan: plan, email } }];
